const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_BASE_PREMIUM = 25;
const BUILDING_BLOCK_PREMIUM = 60;
const FIRST_INSURANCE_SURCHARGE = 1.1;
const PROCESSING_FEE = 5;

export function processScenario(scenario: any): { results: unknown[] } {
  const items = scenario.steps[0].items;
  let totalBasePremium = 0;

  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    const mainPremium = BASE_PREMIUMS[item.type];
    if (mainPremium !== undefined) {
      totalBasePremium += mainPremium;
    } else {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    }
  }

  for (const count of Object.values(componentCounts)) {
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    totalBasePremium += blocks * BUILDING_BLOCK_PREMIUM + remainder * COMPONENT_BASE_PREMIUM;
  }

  const premium = Math.round(totalBasePremium * FIRST_INSURANCE_SURCHARGE) + PROCESSING_FEE;
  return { results: [{ premium }] };
}

