import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting a premium", () => {
    it("should calculate base premium for a single sword for a first-time customer", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // base 100G, first-insurance surcharge +10% = 110G, + 5G fee = 115G
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("should calculate base premium for a single amulet for a first-time customer", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "amulet", material: "silver", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // base 60G, first-insurance surcharge +10% = 66G, + 5G fee = 71G
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it("should calculate base premium for a single staff and a single potion together for a first-time customer", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "staff", material: "wood", enchantment: 0, cursed: false },
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // base 80G + 40G = 120G, first-insurance surcharge +10% = 132G, + 5G fee = 137G
      expect(result.results[0]).toEqual({ premium: 137 });
    });
    it("should calculate base premium for a single component for a first-time customer", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // component base 25G, first-insurance surcharge +10% = 27.5 → ceil 28G, + 5G fee = 33G
      expect(result.results[0]).toEqual({ premium: 33 });
    });
    it("should apply building block discount when 3 alike components are present (60G instead of 75G)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // 3 alike components = building block: 60G instead of 75G
      // first-insurance surcharge +10% = 66G, + 5G fee = 71G
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it("should add 50% surcharge for a cursed item", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: true },
            ],
          },
        ],
      });
      // base 100G, cursed +50% = 150G, first-insurance surcharge +10% = 165G, + 5G fee = 170G
      expect(result.results[0]).toEqual({ premium: 170 });
    });
    it.todo("should add 30% surcharge for an item with enchantment level >= 5");
    it.todo("should apply both cursed and high-enchantment surcharges on the same item");
    it.todo("should apply 20% loyalty discount for a customer with >= 2 years");
    it.todo("should apply 10% initial assessment surcharge for a first insurance (0 prior contracts)");
    it.todo("should apply 15% discount on each contract after the first");
    it.todo("should round premiums in MHPCO's favor (ceiling)");
  });

  describe("Processing a claim", () => {
    it.todo("should apply 100G deductible to a single damage event");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse damage to items with enchantment >= 8 at 50%");
    it.todo("should fully reimburse damage to items made of dragon material regardless of enchantment");
    it.todo("should track remaining cap across multiple claims on the same policy");
    it.todo("should round payouts in MHPCO's favor (floor)");
  });

  describe("Scenario processing", () => {
    it.todo("should process a quote step and return premium in results");
    it.todo("should process a claim step referencing a prior quote and return payout and remainingCap");
    it.todo("should process multiple steps sequentially in a single scenario");
  });
});

