      expect(result.results[0]).toEqual({ premium: 93 });
    });
    it("should apply 10% initial assessment surcharge for a first insurance (0 prior contracts)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // base 40G, first-insurance surcharge +10% = 44G, + 5G fee = 49G
      expect(result.results[0]).toEqual({ premium: 49 });
    });
    it("should apply 15% discount on each contract after the first", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 0, cursed: false },
            ],
          },
        ],
      });
      // First contract: base 100G, first-insurance +10% = 110G, + 5G = 115G
      // Second contract: base 100G, 15% discount = 85G, + 5G = 90G
      expect(result.results[0]).toEqual({ premium: 115 });
      expect(result.results[1]).toEqual({ premium: 90 });
    });
    it("should round premiums in MHPCO's favor (ceiling)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "potion", material: "glass", enchantment: 5, cursed: false },
            ],
          },
        ],
      });
      // base 40G, enchantment +30% = 52G, first-insurance +10% = 57.2G
      // ceiling → 58G, + 5G fee = 63G
      expect(result.results[0]).toEqual({ premium: 63 });
    });
  });

  describe("Processing a claim", () => {
    it.todo("should apply 100G deductible to a single damage event");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should reimburse damage to items with enchantment >= 8 at 50%");
    it.todo("should fully reimburse damage to items made of dragon material regardless of enchantment");
    it.todo("should track remaining cap across multiple claims on the same policy");
    it.todo("should round payouts in MHPCO's favor (floor)");
  });

  describe("Scenario processing", () => {
    it.todo("should process a quote step and return premium in results");
    it.todo("should process a claim step referencing a prior quote and return payout and remainingCap");
    it.todo("should process multiple steps sequentially in a single scenario");
  });
});

